/*
 * PIPELINE CONTEXT INITIALISER
 * ──────────────────────────────────────────────────────────────────
 * Generates all date ranges, IDs, and configuration that downstream
 * nodes depend on. Single source of truth for the entire run.
 */

const now       = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const pad  = (n) => String(n).padStart(2, '0');
const ymd  = (d) => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const iso  = (d) => d.toISOString();

const reportDate  = ymd(yesterday);
const pipelineId  = `ETL-${reportDate}-${now.getTime().toString(36).toUpperCase()}`;
const traceId     = `tr-etl-${now.getTime().toString(36)}`;

return [{
  json: {
    pipelineId,
    traceId,
    reportDate,
    runDate:   ymd(now),
    startTime: iso(now),
    window: {
      from:    `${reportDate}T00:00:00Z`,
      to:      `${reportDate}T23:59:59Z`,
      fromEpoch: Math.floor(new Date(`${reportDate}T00:00:00Z`).getTime() / 1000),
      toEpoch:   Math.floor(new Date(`${reportDate}T23:59:59Z`).getTime() / 1000)
    },
    sources:  ['analytics', 'crm', 'revenue'],
    results:  {},   // populated per-source
    quality:  {},   // quality flags per-source
    errors:   []
  }
}];

/*
 * ETL TRANSFORM + KPI ENGINE
 * ──────────────────────────────────────────────────────────────────
 * - Defensive extraction: every source is optional (circuit-breaker pattern)
 * - Data quality flags: GOOD / DEGRADED / MISSING per source
 * - Computed KPIs require explicit null handling
 * - All numbers rounded at output layer, never during calculation
 */

const items   = $input.all();
const ctx     = items[0].json;   // pipeline context from InitContext
const anaResp = items[1]?.json;  // analytics HTTP response
const crmResp = items[2]?.json;  // crm HTTP response
const revResp = items[3]?.json;  // revenue HTTP response

// ── Quality assessment helper ──────────────────────────────────────
const assess = (resp, requiredKey) => {
  if (!resp) return { status: 'MISSING', data: {} };
  const ok  = resp.statusCode >= 200 && resp.statusCode < 300;
  const raw = resp.body ?? {};
  if (!ok)              return { status: 'ERROR',    data: {}, httpStatus: resp.statusCode };
  if (!raw[requiredKey]) return { status: 'DEGRADED', data: raw };
  return { status: 'GOOD', data: raw };
};

// ── Source extraction ─────────────────────────────────────────────
const ana = assess(anaResp, 'sessions');
const crm = assess(crmResp, 'new_contacts');
const rev = assess(revResp, 'data');

// ── Safe math ─────────────────────────────────────────────────────
const safe = (v, fallback = 0) => (typeof v === 'number' && isFinite(v)) ? v : fallback;
const pct  = (n, d)  => d > 0 ? (n / d) * 100 : 0;
const avg  = (n, d)  => d > 0 ? n / d : 0;
const r2   = (n)      => Math.round(n * 100) / 100;
const r0   = (n)      => Math.round(n);

// ── Analytics metrics ─────────────────────────────────────────────
const ad = ana.data;
const analytics = {
  pageviews:           safe(ad.pageviews),
  sessions:            safe(ad.sessions),
  conversions:         safe(ad.conversions),
  newUsers:            safe(ad.new_users),
  returningUsers:      safe(ad.returning_users),
  bounceRate:          r2(safe(ad.bounce_rate)),
  avgSessionDuration:  r0(safe(ad.avg_session_duration)),
  conversionRate:      r2(pct(safe(ad.conversions), safe(ad.sessions))),
  dataQuality:         ana.status
};

// ── CRM metrics ────────────────────────────────────────────────────
const cd = crm.data;
const crmMetrics = {
  newContacts:         safe(cd.new_contacts),
  dealsCreated:        safe(cd.deals_created),
  dealsClosed:         safe(cd.deals_closed),
  pipelineValue:       r2(safe(cd.pipeline_value)),
  activitiesLogged:    safe(cd.activities_logged),
  closeRate:           r2(pct(safe(cd.deals_closed), safe(cd.deals_created))),
  avgDealSize:         r2(avg(safe(cd.pipeline_value), safe(cd.deals_created))),
  dataQuality:         crm.status
};

// ── Revenue metrics ────────────────────────────────────────────────
const txns   = Array.isArray(rev.data?.data) ? rev.data.data : [];
const charges = txns.filter(t => t.type === 'charge');
const refunds = txns.filter(t => t.type === 'refund');

const grossRevenue = charges.reduce((s,t) => s + safe(t.amount) / 100, 0);
const totalRefunds = refunds.reduce((s,t) => s + safe(t.amount) / 100, 0);
const netRevenue   = grossRevenue - totalRefunds;
const txnCount     = charges.length;

const revenueMetrics = {
  grossRevenue:      r2(grossRevenue),
  totalRefunds:      r2(totalRefunds),
  netRevenue:        r2(netRevenue),
  refundRate:        r2(pct(refunds.length, txnCount)),
  transactionCount:  txnCount,
  refundCount:       refunds.length,
  avgTransactionValue: r2(avg(grossRevenue, txnCount)),
  dataQuality:       rev.status
};

// ── Composite KPIs (require multiple sources) ─────────────────────
const kpis = {
  revenuePerSession:        r2(avg(netRevenue, analytics.sessions)),
  revenuePerNewContact:     r2(avg(netRevenue, crmMetrics.newContacts)),
  leadToCloseRate:          r2(pct(crmMetrics.dealsClosed, crmMetrics.newContacts)),
  costPerConversion:        null, // requires spend data — placeholder
  dataCompleteness:         `${[ana.status, crm.status, rev.status].filter(s => s === 'GOOD').length}/3`
};

// ── Pipeline quality decision ──────────────────────────────────────
const goodSources = [ana.status, crm.status, rev.status].filter(s => s === 'GOOD').length;
const pipelineStatus = goodSources === 3 ? 'COMPLETE'
  : goodSources >= 2 ? 'DEGRADED'
  : 'FAILED';

return [{
  json: {
    ...ctx,
    pipelineStatus,
    analytics,
    crm:     crmMetrics,
    revenue: revenueMetrics,
    kpis,
    sourceQuality: { analytics: ana.status, crm: crm.status, revenue: rev.status },
    transformedAt: new Date().toISOString()
  }
}];

// Merge pipeline data + AI summary; compute final runtime stats
const pipeline = $input.all()[0].json;
const summary  = $input.all()[1]?.json?.message?.content ?? 'Summary unavailable — check source data quality.';

const durationMs = Date.now() - new Date(pipeline.startTime).getTime();

return [{
  json: {
    ...pipeline,
    aiSummary: summary,
    durationMs,
    durationSec: Math.round(durationMs / 1000)
  }
}];
